void tvsub(struct timeval *time1, struct timeval *time0, struct timeval *result)
{
    result->tv_sec = time1->tv_sec - time0->tv_sec;
    result->tv_usec = time1->tv_usec - time0->tv_usec;
    if (result->tv_usec < 0) {
        result->tv_sec--;
        result->tv_usec += 1000000;
    }
